package libravdb

import (
	"context"
	"encoding/base64"
	"errors"
	"os"
	"path/filepath"
	"testing"
)

// This is a minimal valid v1.0.1 database file with one collection ("test_col")
// and one vector ("vec1", [1, 2, 3]).
const testV1Payload = ``

func TestAutoMigrationV1ToV2(t *testing.T) {
	tempDir := t.TempDir()
	dbPath := filepath.Join(tempDir, "test.libravdb")

	data, err := base64.StdEncoding.DecodeString(testV1Payload)
	if err != nil {
		t.Fatalf("failed to decode v1 payload: %v", err)
	}

	if err := os.WriteFile(dbPath, data, 0644); err != nil {
		t.Fatalf("failed to write v1 payload: %v", err)
	}

	// Calling Open should automatically trigger migration
	db, err := Open(WithStoragePath(dbPath))
	if err != nil {
		t.Fatalf("failed to auto-migrate database: %v", err)
	}
	defer db.Close()

	// Verify the backup file exists
	backupPath := dbPath + ".v1.bak"
	if _, err := os.Stat(backupPath); err != nil {
		t.Fatalf("backup file not found: %v", err)
	}

	// Verify the data was migrated correctly
	col, err := db.GetCollection("test_col")
	if err != nil {
		t.Fatalf("failed to get migrated collection: %v", err)
	}

	entry, err := col.Get(context.Background(), "vec1")
	if err != nil {
		t.Fatalf("Get failed: %v", err)
	}
	if len(entry.Vector) != 3 {
		t.Errorf("expected vector dimension 3, got %d", len(entry.Vector))
	}
	if entry.Vector[0] != 1 || entry.Vector[1] != 2 || entry.Vector[2] != 3 {
		t.Errorf("unexpected vector values: %v", entry.Vector)
	}
}

func TestReplaceFileDurablyReportsRenameBeforeSyncFailure(t *testing.T) {
	dir := t.TempDir()
	oldPath := filepath.Join(dir, "old")
	newPath := filepath.Join(dir, "new")
	if err := os.WriteFile(oldPath, []byte("payload"), 0o600); err != nil {
		t.Fatal(err)
	}
	syncErr := errors.New("sync failed")
	renamed, err := replaceFileDurablyWith(oldPath, newPath, func(string) error { return syncErr })
	if !renamed {
		t.Fatal("rename completion was not reported")
	}
	if !errors.Is(err, syncErr) {
		t.Fatalf("error = %v, want sync failure", err)
	}
	if _, err := os.Stat(newPath); err != nil {
		t.Fatalf("renamed file missing: %v", err)
	}
	if _, err := os.Stat(oldPath); !os.IsNotExist(err) {
		t.Fatalf("old path still exists after rename: %v", err)
	}
}

func TestRecoverMigrateActivatesStagedFile(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "database.libravdb")
	stagedPath := path + ".staged"
	backupPath := path + ".v1.bak"
	if err := os.WriteFile(stagedPath, []byte("new"), 0o600); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(backupPath, []byte("old"), 0o600); err != nil {
		t.Fatal(err)
	}
	if err := recoverMigrate(path); err != nil {
		t.Fatalf("recoverMigrate: %v", err)
	}
	data, err := os.ReadFile(path)
	if err != nil {
		t.Fatalf("read activated file: %v", err)
	}
	if string(data) != "new" {
		t.Fatalf("activated payload = %q, want new", data)
	}
	if _, err := os.Stat(stagedPath); !os.IsNotExist(err) {
		t.Fatalf("staged path still exists: %v", err)
	}
}
